{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMZdJwFMj1XQmPjqVoCHTHL"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"vRdws_lno_-h"},"outputs":[],"source":["import numpy as np\n","from scipy import sparse\n","from scipy.sparse.linalg import spsolve\n","\n","class FVMSolver:\n","    def __init__(self, config, mesh):\n","        self.cfg = config\n","        self.mesh = mesh\n","        self.N = config.NR * config.NZ\n","\n","    def solve_step(self, T_old, T_amb, dt):\n","        A = sparse.lil_matrix((self.N, self.N))\n","        B = np.zeros(self.N)\n","\n","        rho_cp_V_dt = (self.cfg.RHO * self.cfg.CP * self.mesh.V) / dt\n","\n","        for i in range(self.cfg.NR):\n","            for j in range(self.cfg.NZ):\n","                idx = i * self.cfg.NZ + j\n","                aw, ae, asub, an = 0, 0, 0, 0\n","\n","                # West (Inner) / East (Outer)\n","                if i > 0: aw = self.cfg.K_THERM * self.mesh.area_w[i,j] / self.mesh.dr\n","                if i < self.cfg.NR - 1:\n","                    ae = self.cfg.K_THERM * self.mesh.area_e[i,j] / self.mesh.dr\n","                else:\n","                    B[idx] += self.cfg.H_CONV * self.mesh.area_e[i,j] * T_amb\n","\n","                # South (Bottom) / North (Top)\n","                if j > 0: asub = self.cfg.K_THERM * self.mesh.area_s[i,j] / self.mesh.dz\n","                else: B[idx] += self.cfg.H_CONV * self.mesh.area_s[i,j] * T_amb\n","\n","                if j < self.cfg.NZ - 1: an = self.cfg.K_THERM * self.mesh.area_n[i,j] / self.mesh.dz\n","\n","                ap0 = rho_cp_V_dt[i, j]\n","                ap = aw + ae + asub + an + ap0\n","                # Boundary adjustments to ap\n","                if i == self.cfg.NR - 1: ap += self.cfg.H_CONV * self.mesh.area_e[i,j]\n","                if j == 0: ap += self.cfg.H_CONV * self.mesh.area_s[i,j]\n","\n","                A[idx, idx] = ap\n","                if i > 0: A[idx, idx - self.cfg.NZ] = -aw\n","                if i < self.cfg.NR - 1: A[idx, idx + self.cfg.NZ] = -ae\n","                if j > 0: A[idx, idx - 1] = -asub\n","                if j < self.cfg.NZ - 1: A[idx, idx + 1] = -an\n","\n","                B[idx] += ap0 * T_old[i, j]\n","\n","        T_new = spsolve(A.tocsr(), B)\n","        return T_new.reshape((self.cfg.NR, self.cfg.NZ))"]}]}